const width = param("Width", 120, { min: 80, max: 180, unit: "mm" });
const depth = param("Depth", 80, { min: 50, max: 140, unit: "mm" });
const height = param("Height", 14, { min: 8, max: 30, unit: "mm" });

const base = roundedRect(width, depth, 10)
  .extrude(height)
  .color("#5f87c6");

show(base);

const pocket = roundedRect(width - 24, depth - 24, 8)
  .extrude(height - 3)
  .translate(12, 12, 3)
  .color("#d67a61");

show([
  { name: "Base", shape: base },
  { name: "Pocket", shape: pocket },
]);

const part = base.subtract(pocket);

dim([0, 0, 0], [width, 0, 0], { label: "Width" });
dim([0, 0, 0], [0, depth, 0], { label: "Depth", offset: 14 });
cutPlane("Center Section", [1, 0, 0], width / 2);

return part;
